object AppLog {

    private const val TAG_AUTH = "AUTH"
    private const val TAG_DB = "DB"
    private const val TAG_API = "API"
    private const val TAG_EX = "EX"

    fun v(tag: String, msg: String) = Timber.tag(tag).v(msg)
    fun d(tag: String, msg: String) = Timber.tag(tag).d(msg)
    fun i(tag: String, msg: String) = Timber.tag(tag).i(msg)
    fun w(tag: String, msg: String, t: Throwable? = null) = if (t != null) Timber.tag(tag).w(t, msg) else Timber.tag(tag).w(msg)
    fun e(tag: String, msg: String, t: Throwable? = null) = if (t != null) Timber.tag(tag).e(t, msg) else Timber.tag(tag).e(msg)

    fun authAttempt(
        usernameOrId: String?,
        method: String,
        success: Boolean,
        reason: String? = null,
        metadata: Map<String, Any?> = emptyMap()
    ) {
        val id = usernameOrId ?: "<null>"
        val meta = metadata.entries.joinToString(prefix = "{", postfix = "}") { "${it.key}=${it.value}" }
        val msg = buildString {
            append("auth_attempt method=").append(method)
            append(" user=").append(id)
            append(" success=").append(success)
            if (!reason.isNullOrBlank()) append(" reason=").append(reason)
            if (metadata.isNotEmpty()) append(" meta=").append(meta)
        }
        Timber.tag(TAG_AUTH).i(msg)
    }

    fun authSuccess(usernameOrId: String?, method: String, metadata: Map<String, Any?> = emptyMap()) {
        authAttempt(usernameOrId, method, success = true, reason = null, metadata = metadata)
    }

    fun authFailure(usernameOrId: String?, method: String, reason: String, metadata: Map<String, Any?> = emptyMap()) {
        authAttempt(usernameOrId, method, success = false, reason = reason, metadata = metadata)
    }

    fun dbQuery(
        dbName: String,
        sql: String,
        args: List<Any?> = emptyList(),
        rows: Int? = null,
        durationMs: Long? = null
    ) {
        val msg = buildString {
            append("db_query db=").append(dbName)
            append(" sql=").append(sql)
            append(" args=").append(args)
            if (rows != null) append(" rows=").append(rows)
            if (durationMs != null) append(" durationMs=").append(durationMs)
        }
        Timber.tag(TAG_DB).v(msg)
    }

    fun dbError(dbName: String, sql: String, args: List<Any?> = emptyList(), t: Throwable) {
        val msg = "db_error db=$dbName sql=$sql args=$args"
        Timber.tag(TAG_DB).e(t, msg)
    }

    fun exception(t: Throwable, context: String? = null, extra: Map<String, Any?> = emptyMap()) {
        val msg = buildString {
            append("exception")
            if (!context.isNullOrBlank()) append(" context=").append(context)
            if (extra.isNotEmpty()) append(" extra=").append(extra)
        }
        Timber.tag(TAG_EX).e(t, msg)
    }
}

class ExceptionLoggingHandler(
    private val delegate: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {
    override fun uncaughtException(t: Thread, e: Throwable) {
        try {
            Timber.tag("CRASH").e(e, "uncaught_exception thread=${t.name} id=${t.id}")
        } catch (_: Throwable) {
        } finally {
            delegate?.uncaughtException(t, e)
        }
    }
}

object CrashLogging {
    fun installUncaughtExceptionHandler() {
        Thread.setDefaultUncaughtExceptionHandler(ExceptionLoggingHandler())
    }
}

class ApiLoggingInterceptor(
    private val tag: String = "API",
    private val logHeaders: Boolean = true,
    private val logBody: Boolean = true,
    private val maxBodyChars: Int = 200_000,
    private val maxHeaderChars: Int = 50_000,
    private val prettyJson: Boolean = true,
    private val redactHeaders: Set<String> = emptySet(),
    private val redactJsonKeys: Set<String> = emptySet()
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val requestId = UUID.randomUUID().toString()
        val request = chain.request()
        val startNs = System.nanoTime()

        logRequest(requestId, request)

        val response: Response = try {
            chain.proceed(request)
        } catch (t: Throwable) {
            Timber.tag(tag).e(t, "api_failure id=$requestId ${request.method} ${request.url}")
            throw t
        }

        val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
        return logResponse(requestId, request, response, tookMs)
    }

    private fun logRequest(id: String, request: Request) {
        val sb = StringBuilder()
        sb.append("api_request id=").append(id)
            .append(" method=").append(request.method)
            .append(" url=").append(request.url)

        if (AppLogging.LoggerConfig.includeDeviceInfo) {
            sb.append(" device=").append(Build.MANUFACTURER).append("/").append(Build.MODEL)
            sb.append(" sdk=").append(Build.VERSION.SDK_INT)
        }

        if (logHeaders) {
            val headersStr = headersToString(request.headers, redactHeaders.ifEmpty { AppLogging.LoggerConfig.redactHeaders })
            sb.append("\nheaders:\n").append(truncate(headersStr, maxHeaderChars))
        }

        if (logBody) {
            val bodyStr = requestBodyToString(request, redactJsonKeys.ifEmpty { AppLogging.LoggerConfig.redactJsonKeys }, prettyJson)
            if (bodyStr != null) {
                sb.append("\nbody:\n").append(truncate(bodyStr, maxBodyChars))
            } else {
                sb.append("\nbody: <none or omitted>")
            }
        }

        Timber.tag(tag).v(sb.toString())
    }

    private fun logResponse(id: String, request: Request, response: Response, tookMs: Long): Response {
        val sb = StringBuilder()
        sb.append("api_response id=").append(id)
            .append(" code=").append(response.code)
            .append(" message=").append(response.message)
            .append(" tookMs=").append(tookMs)
            .append(" method=").append(request.method)
            .append(" url=").append(request.url)

        if (logHeaders) {
            val headersStr = headersToString(response.headers, redactHeaders.ifEmpty { AppLogging.LoggerConfig.redactHeaders })
            sb.append("\nheaders:\n").append(truncate(headersStr, maxHeaderChars))
        }

        if (logBody) {
            val peeked = try {
                response.peekBody(Long.MAX_VALUE)
            } catch (_: Throwable) {
                null
            }
            if (peeked != null) {
                val contentType = peeked.contentType()
                val bodyStr = responseBodyToString(peeked, contentType, redactJsonKeys.ifEmpty { AppLogging.LoggerConfig.redactJsonKeys }, prettyJson)
                sb.append("\nbody:\n").append(truncate(bodyStr, maxBodyChars))
            } else {
                sb.append("\nbody: <unavailable>")
            }
        }

        Timber.tag(tag).v(sb.toString())
        return response
    }

    private fun headersToString(headers: Headers, redact: Set<String>): String {
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = headers.value(i)
            val safeValue = if (redact.contains(name.lowercase())) "<redacted>" else value
            sb.append(name).append(": ").append(safeValue).append("\n")
        }
        return sb.toString().trimEnd()
    }

    private fun requestBodyToString(request: Request, redactKeys: Set<String>, pretty: Boolean): String? {
        val body = request.body ?: return null
        if (body.isDuplex()) return "<duplex body omitted>"
        if (body.isOneShot()) return "<one-shot body omitted>"

        val buffer = Buffer()
        return try {
            body.writeTo(buffer)
            val charset = body.contentType()?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val raw = buffer.readString(charset)
            sanitizeBody(raw, body.contentType(), redactKeys, pretty)
        } catch (e: Exception) {
            "<failed to read request body: ${e::class.java.simpleName}: ${e.message}>"
        }
    }

    private fun responseBodyToString(body: ResponseBody, contentType: MediaType?, redactKeys: Set<String>, pretty: Boolean): String {
        return try {
            val source = body.source()
            source.request(Long.MAX_VALUE)
            val buffer = source.buffer.clone()
            val charset: Charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val raw = buffer.readString(charset)
            sanitizeBody(raw, contentType, redactKeys, pretty)
        } catch (e: EOFException) {
            "<binary body omitted>"
        } catch (e: Exception) {
            "<failed to read response body: ${e::class.java.simpleName}: ${e.message}>"
        }
    }

    private fun sanitizeBody(raw: String, contentType: MediaType?, redactKeys: Set<String>, pretty: Boolean): String {
        if (!isProbablyUtf8(raw)) return "<binary body omitted>"

        val subtype = contentType?.subtype?.lowercase()
        val looksJson = subtype?.contains("json") == true || raw.trimStart().startsWith("{") || raw.trimStart().startsWith("[")
        if (!looksJson) return raw

        val redacted = redactJson(raw, redactKeys.ifEmpty { AppLogging.LoggerConfig.redactJsonKeys })
        if (!pretty) return redacted
        return prettyPrintJsonIfPossible(redacted)
    }

    private fun redactJson(json: String, redactKeys: Set<String>): String {
        val trimmed = json.trim()
        return try {
            if (trimmed.startsWith("{")) {
                val obj = JSONObject(trimmed)
                redactJsonObject(obj, redactKeys)
                obj.toString()
            } else if (trimmed.startsWith("[")) {
                val arr = JSONArray(trimmed)
                redactJsonArray(arr, redactKeys)
                arr.toString()
            } else {
                json
            }
        } catch (_: Throwable) {
            json
        }
    }

    private fun redactJsonObject(obj: JSONObject, redactKeys: Set<String>) {
        val keys = obj.keys()
        while (keys.hasNext()) {
            val k = keys.next()
            val v = obj.opt(k)
            if (redactKeys.contains(k.lowercase())) {
                obj.put(k, "<redacted>")
            } else {
                when (v) {
                    is JSONObject -> redactJsonObject(v, redactKeys)
                    is JSONArray -> redactJsonArray(v, redactKeys)
                }
            }
        }
    }

    private fun redactJsonArray(arr: JSONArray, redactKeys: Set<String>) {
        for (i in 0 until arr.length()) {
            val v = arr.opt(i)
            when (v) {
                is JSONObject -> redactJsonObject(v, redactKeys)
                is JSONArray -> redactJsonArray(v, redactKeys)
            }
        }
    }

    private fun prettyPrintJsonIfPossible(json: String): String {
        val trimmed = json.trim()
        return try {
            when {
                trimmed.startsWith("{") -> JSONObject(trimmed).toString(2)
                trimmed.startsWith("[") -> JSONArray(trimmed).toString(2)
                else -> json
            }
        } catch (_: Throwable) {
            json
        }
    }

    private fun isProbablyUtf8(s: String): Boolean {
        for (i in 0 until min(64, s.length)) {
            val c = s[i]
            if (c == '\uFFFD') return false
        }
        return true
    }

    private fun truncate(s: String, max: Int): String {
        if (s.length <= max) return s
        return s.substring(0, max) + "\n<truncated ${s.length - max} chars>"
    }
}

@Keep
class DbLogger(private val dbName: String) {

    suspend fun <T> runQuery(
        sql: String,
        args: List<Any?> = emptyList(),
        block: suspend () -> T
    ): T {
        val start = System.nanoTime()
        return try {
            val result = withContext(Dispatchers.IO) { block() }
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLog.dbQuery(dbName = dbName, sql = sql, args = args, durationMs = tookMs)
            result
        } catch (t: Throwable) {
            AppLog.dbError(dbName = dbName, sql = sql, args = args, t = t)
            throw t
        }
    }

    fun query(sql: String, args: List<Any?> = emptyList(), rows: Int? = null, durationMs: Long? = null) {
        AppLog.dbQuery(dbName = dbName, sql = sql, args = args, rows = rows, durationMs = durationMs)
    }

    fun error(sql: String, args: List<Any?> = emptyList(), t: Throwable) {
        AppLog.dbError(dbName = dbName, sql = sql, args = args, t = t)
    }
}

